# Module providing data structures
enum Status:
    PENDING = 0
    ACTIVE = 1
    INACTIVE = 2

struct Dimensions:
    width: float
    height: float

    def __init__(self, width: float, height: float):
        self.width = width
        self.height = height

    def area(self) -> float:
        return self.width * self.height

    @static
    def square(size: float) -> Dimensions:
        return Dimensions(size, size)

class Item:
    # Use public fields for direct access
    label: str
    dimensions: Dimensions

    def __init__(self, label: str, dims: Dimensions):
        self.label = label
        self.dimensions = dims

