# Module providing core utility interfaces and base classes
from module_data import Status, Dimensions

# Interfaces define what methods/classes must provide
interface IIdentifiable:
    def get_id(self) -> int

interface INameable:
    def get_name(self) -> str

# Entity implements IIdentifiable with a method
class Entity(IIdentifiable):
    _id: int

    def __init__(self, id: int):
        self._id = id

    def get_id(self) -> int:
        return self._id

# NamedEntity extends Entity and implements INameable
class NamedEntity(Entity, INameable):
    _name: str

    def __init__(self, id: int, name: str):
        super().__init__(id)
        self._name = name

    def get_id(self) -> int:
        # Override to add 1000
        return self._id + 1000

    def get_name(self) -> str:
        return self._name

    def describe(self) -> str:
        return "Entity " + self._name + " has ID " + str(self.get_id())

    def get_status(self) -> Status:
        return Status.ACTIVE

