# Module providing helper functions
from module_data import Dimensions

def double_value(x: int) -> int:
    return x * 2

def format_dimensions(d: Dimensions) -> str:
    # Access struct fields directly
    x_str: str = str(d.width)
    y_str: str = str(d.height)
    return x_str + "x" + y_str

def process_int_items(items: list[int], processor: (int) -> str) -> list[str]:
    result: list[str] = []
    for item in items:
        result.append(processor(item))
    return result

def calculate_total_area(dims_list: list[Dimensions]) -> float:
    total: float = 0.0
    for d in dims_list:
        total = total + d.area()
    return total

def describe_items(items: list[Item]) -> list[str]:
    result: list[str] = []
    for item in items:
        result.append(item.label)
    return result
